import{_ as t,o,c as i,a3 as n}from"./chunks/framework.DACwFHq9.js";const h=JSON.parse('{"title":"Peer-to-Peer Sync","description":"Sync notes securely between devices using peer-to-peer pairing over local networks.","frontmatter":{"title":"Peer-to-Peer Sync","description":"Sync notes securely between devices using peer-to-peer pairing over local networks.","keywords":"P2P, sync, peer-to-peer, discovery, invite code, conflict resolution","category":"Sync"},"headers":[],"relativePath":"sync/index.md","filePath":"sync/index.md","lastUpdated":1784869909000}'),r={name:"sync/index.md"};function a(s,e,l,c,d,p){return o(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="p2p-sync" tabindex="-1">P2P Sync <a class="header-anchor" href="#p2p-sync" aria-label="Permalink to &quot;P2P Sync&quot;">​</a></h1><p>Notely includes peer-to-peer (P2P) sync, allowing you to replicate notes between devices directly without storing data in the cloud.</p><h2 id="_1-how-it-works" tabindex="-1">1. How it Works <a class="header-anchor" href="#_1-how-it-works" aria-label="Permalink to &quot;1. How it Works&quot;">​</a></h2><p>Syncing operates over local networks:</p><ul><li>Devices discover each other using local broadcast protocols.</li><li>Content is encrypted end-to-end.</li><li>Workspace encryption keys are shared during initial pairing.</li></ul><hr><h2 id="_2-pairing-devices" tabindex="-1">2. Pairing Devices <a class="header-anchor" href="#_2-pairing-devices" aria-label="Permalink to &quot;2. Pairing Devices&quot;">​</a></h2><ol><li>Open <strong>P2P → P2P Status</strong> on both devices.</li><li>Click <strong>Start Discovery</strong> to scan the local network.</li><li>On one device, generate an Invite Code.</li><li>On the second device, click <strong>Pair with Peer</strong> and input the code.</li><li>Once accepted, add the device to your <strong>Trusted Peers</strong> list.</li></ol><hr><h2 id="_3-conflict-resolution" tabindex="-1">3. Conflict Resolution <a class="header-anchor" href="#_3-conflict-resolution" aria-label="Permalink to &quot;3. Conflict Resolution&quot;">​</a></h2><p>If a note is edited on two devices simultaneously before sync completes:</p><ol><li>Notely halts automated merges for that note and flags a conflict.</li><li>Open the <strong>Conflict Resolution Panel</strong> from the P2P status bar indicator.</li><li>Compare the conflicting versions side-by-side.</li><li>Select <strong>Keep Local</strong>, <strong>Keep Remote</strong>, or <strong>Merge Manually</strong> to resolve.</li></ol><hr><h2 id="_4-key-rotation-security" tabindex="-1">4. Key Rotation &amp; Security <a class="header-anchor" href="#_4-key-rotation-security" aria-label="Permalink to &quot;4. Key Rotation &amp; Security&quot;">​</a></h2><ul><li><strong>Rotate Keys</strong>: Generate new workspace encryption keys from the P2P Settings.</li><li><strong>Revoke Peers</strong>: Untrust a device at any time to block future sync requests.</li></ul>',15)])])}const y=t(r,[["render",a]]);export{h as __pageData,y as default};
